function __cityLbl(en){try{if(typeof __ar==='function'&&__ar()){const m=LIBYA_CITIES.find(c=>c.en===en);if(m)return m.ar;}}catch(e){}return en;}
function addCity(code,cityVal){let city=cityVal;if(!city){const id='new-city-'+code;const el=document.getElementById(id);city=el?el.value.trim():'';if(el)el.value='';}if(!city||!zones[code]||zones[code].cities[city])return;zones[code].cities[city]={delivery:''};renderZoneBuilderList();}
function removeCity(code,city){delete zones[code].cities[city];renderZoneBuilderList();}
function updateCityCost(code,city,field,val){if(zones[code]&&zones[code].cities[city])zones[code].cities[city][field]=parseFloat(val)||0;}
function updateZoneShipping(code,val){if(zones[code])zones[code].shipping=val===''?'':(parseFloat(val)||0);}
function renderZoneBuilderList(){const el=document.getElementById('zone-builder-list');const keys=Object.keys(zones);if(!keys.length){el.innerHTML='';return;}const ar=(typeof __ar==='function'&&__ar());const shipLblFor=(name)=>ar?`تكلفة الشحن لـ ${name} (اختياري)`:`Shipping cost for ${name} (optional)`;const cityLbl=ar?'المدينة':'City';const dlvLbl=ar?'تكلفة التوصيل':'Delivery cost';el.innerHTML=keys.map(code=>{const z=zones[code];const ck=Object.keys(z.cities);const isLY=code==='LY';const countryMeta=COUNTRIES.find(c=>c.code===code);const flag=countryMeta?countryMeta.flag:'\ud83c\udf10';const cname=COUNTRY_NAMES[code]||code;let adder;if(isLY){const avail=LIBYA_CITIES.filter(c=>!z.cities[c.en]);const placeholder=ar?'اختر مدينة…':'Select a city…';adder=`<select id="new-city-${code}" onchange="if(this.value){addCity('${code}',this.value);this.value='';}" style="width:100%;padding:11px 12px;font-size:13px;border:1.5px dashed var(--color-border-secondary);border-radius:12px;background:transparent;color:#2dbd8f;font-weight:700;outline:none;font-family:var(--font-sans);margin-top:10px;"><option value="">${placeholder}</option>${avail.map(c=>`<option value="${c.en.replace(/"/g,'&quot;')}">${__cityLbl(c.en)}</option>`).join('')}</select>`;}else{adder=`<div style="display:flex;gap:6px;margin-top:10px"><input id="new-city-${code}" type="text" placeholder="${ar?'أضف مدينة…':'Add a city…'}" style="flex:1;padding:9px 10px;font-size:13px;border:0.5px solid var(--color-border-secondary);border-radius:10px;background:var(--color-background-primary);color:var(--color-text-primary);outline:none;font-family:var(--font-sans);" onkeydown="if(event.key==='Enter'){event.preventDefault();addCity('${code}');}"/><button onclick="addCity('${code}')" style="height:38px;padding:0 14px;border-radius:10px;border:none;background:#2dbd8f;color:#fff;font-size:12px;font-weight:600;cursor:pointer;font-family:var(--font-sans);">${ar?'إضافة':'Add'}</button></div>`;}const shipRow=`<div class="lp-cost-row"><span class="cost-label">${shipLblFor(cname)}</span><input type="number" value="${z.shipping===''||z.shipping==null?'':z.shipping}" placeholder="0.00" step="0.01" onchange="updateZoneShipping('${code}',this.value)"/></div>`;const cityRows=ck.map(city=>`<div class="lp-city-row-flex"><span class="city-name">${isLY?__cityLbl(city):city} <span class="x-mark" onclick="removeCity('${code}','${city}')">✕</span></span><input type="number" value="${z.cities[city].delivery||''}" placeholder="0.00" step="0.01" onchange="updateCityCost('${code}','${city}','delivery',this.value)"/></div>`).join('');return`<div class="lp-country-card-2"><div class="lp-country-card-head"><span>${flag} ${cname}</span><span class="rm" onclick="removeZone('${code}')">✕</span></div>${shipRow}${ck.length?`<div class="lp-city-values-label"><span>${cityLbl}</span><span>${dlvLbl}</span></div>${cityRows}`:''}${adder}</div>`;}).join('');}
function hydrateVariantGroups(p){const __szPh=__ar()?'مثال: المقاس':'Example: Size';const __clPh=__ar()?'مثال: اللون':'Example: Color';const __norm=v=>({id:variantIdCounter++,val:typeof v==='string'?v:(v&&v.val)||'',qty:(v&&typeof v==='object'&&v.qty)||'',photo:(v&&typeof v==='object'&&v.photo)||''});if(!p)return[{id:groupIdCounter++,name:'',placeholder:__szPh,items:[{id:variantIdCounter++,val:'',qty:'',photo:''}]},{id:groupIdCounter++,name:'',placeholder:__clPh,items:[{id:variantIdCounter++,val:'',qty:'',photo:''}]}];if(p.variantGroups&&p.variantGroups.length)return p.variantGroups.map(g=>({id:groupIdCounter++,name:g.name,placeholder:'Variant name',items:(g.items||[]).map(__norm)}));const out=[];out.push({id:groupIdCounter++,name:__ar()?'المقاسات':'Sizes',placeholder:__szPh,items:(p.sizes||[]).map(__norm)});out.push({id:groupIdCounter++,name:__ar()?'الألوان':'Colours',placeholder:__clPh,items:(p.colors||[]).map(__norm)});return out;}
function ensureUniqueCode(existing){let c=existing||genCode();const taken=new Set((products||[]).map(x=>x.code));let guard=0;while(taken.has(c)&&guard<50){c=genCode();guard++;}return c;}
function openAddForm(p){photos=p?[...(p.photos||[])]:[];variantGroups=hydrateVariantGroups(p);zones=p?JSON.parse(JSON.stringify(p.delivery)):{};Object.keys(zones).forEach(code=>{const z=zones[code];if(!z.cities)z.cities={};let s=0;Object.values(z.cities).forEach(c=>{const cs=Number(c.shipping)||0;if(cs>s)s=cs;});if(z.shipping==null||z.shipping==='')z.shipping=s||'';});commMode=p?.commMode||'pct';selectedCurrency=p?.currency||null;currentCode=ensureUniqueCode(p?.code);document.getElementById('product-code-display').textContent=currentCode;document.getElementById('form-title').textContent=p?'Edit product':'Add a product';document.getElementById('f-name').value=p?.name||'';document.getElementById('f-desc').value=p?.desc||'';document.getElementById('f-price').value=p?.price||'';document.getElementById('f-cost').value=p?.costPrice||'';selectedCategory=p?.category||'';const catVal=document.getElementById('category-picker-value');if(selectedCategory){catVal.textContent=selectedCategory;catVal.classList.remove('placeholder');}else{catVal.textContent='Select category';catVal.classList.add('placeholder');}document.getElementById('f-comm-pct').value=p?.commPct||'';document.getElementById('f-comm-fixed').value=p?.commFixed||'';if(selectedCurrency){document.getElementById('curr-flag').textContent=selectedCurrency.flag;document.getElementById('curr-name').textContent=selectedCurrency.name+' ('+selectedCurrency.code+')';document.getElementById('curr-symbol-label').textContent=selectedCurrency.symbol;document.getElementById('price-prefix').textContent=selectedCurrency.symbol;document.getElementById('comm-curr-suffix').textContent=selectedCurrency.symbol;}else{document.getElementById('curr-flag').textContent='🌐';document.getElementById('curr-name').textContent='Select a currency';document.getElementById('curr-symbol-label').textContent='';document.getElementById('price-prefix').textContent='—';document.getElementById('comm-curr-suffix').textContent='—';}setCommMode(commMode);renderPhotoGrid();renderVariantGroups();renderZoneBuilderList();updateConversionNote();updateProductSummaryCard();document.getElementById('form-overlay').classList.add('open');}
function closeForm(){document.getElementById('form-overlay').classList.remove('open');editingId=null;photos=[];variantGroups=[];zones={};selectedCurrency=null;selectedCategory='';currDropdownOpen=false;countryDropdownOpen=false;closeCategoryPanel();}
